/****** Object:  View [dbo].[ClassificationHierarchyView]    Script Date: 2021/11/03 04:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
IF NOT EXISTS (SELECT * FROM sys.views WHERE object_id = OBJECT_ID(N'[dbo].[ClassificationHierarchyView]'))
EXEC dbo.sp_executesql @statement = N'


--drop view [dbo].[SecurityHierarchyView];
CREATE view [dbo].[ClassificationHierarchyView]
AS
    with tbl AS
    (
    select st.ClassificationID        ''id''
    , st.ClassificationName      ''name''
    , sxs.ParentClassificationID ''ParentID''
    from Classification.ClassificationXClassification sxs (nolock)
    right outer join Classification.Classification st (nolock)
    on sxs.ChildClassificationID = st.ClassificationID
    left join Classification.Classification stChild (nolock)
    on sxs.ChildClassificationID = stChild.ClassificationID
),
    SecurityPath
AS (
    -- anchor
    SELECT CONVERT(VARCHAR(36),id) id,
    CONVERT(VARCHAR(36),[Name]) [Name],
    CONVERT(VARCHAR(36),ParentID) ParentID,
    CONVERT(VARCHAR(1500),[Name]) AS "Pather",
    CONVERT(VARCHAR(1500),id)  AS "Path"
    FROM tbl
    WHERE ParentId IS NULL
    UNION ALL
    --recursive member
    SELECT  CONVERT(VARCHAR(36),t.id) id,
    CONVERT(VARCHAR(36),t.[Name]) [Name],
    CONVERT(VARCHAR(36),t.ParentID) ParentID,
    CAST(CONVERT(VARCHAR(36),a.name) + ''/'' + (CONVERT(VARCHAR(36),t.Name)) AS VARCHAR(1500)) AS "Path",
    CAST((a."Path" + ''/'' + convert(VARCHAR(36),t.id)) AS VARCHAR(1500)) AS "PathCrypt"
    FROM tbl AS t
    JOIN SecurityPath AS a
    ON t.ParentId = a.id
)
SELECT s.id, s.Name, s.ParentID, s.Pather, s.Path, ''1'' as ''One''
FROM SecurityPath s
' 
GO
/****** Object:  View [dbo].[LU_Classifications]    Script Date: 2021/11/03 04:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
IF NOT EXISTS (SELECT * FROM sys.views WHERE object_id = OBJECT_ID(N'[dbo].[LU_Classifications]'))
EXEC dbo.sp_executesql @statement = N'CREATE VIEW [dbo].[LU_Classifications]
AS
select distinct cdc.ClassificationDataConceptID,cdc.ClassificationDataConceptName,
                c.ClassificationID ''Level1ID'',c.ClassificationName ''Level1Name'',
                cDesc.ClassificationID  ''Level2ID'',cDesc.ClassificationName''Level2Name'',
                cDesc2.ClassificationID ''Level3ID'',cDesc2.ClassificationName''Level3Name'',
                cDesc3.ClassificationID ''Level4ID'',cDesc3.ClassificationName''Level4Name'',
                cDesc4.ClassificationID ''Level5ID'',cDesc4.ClassificationName''Level5Name''
from Classification.Classification c
         left join Classification.ClassificationXClassification cxc
                   on c.ClassificationID = cxc.ParentClassificationID
         left join ClassificationHierarchyView chv
                   on c.ClassificationID = chv.ParentID
    outer apply dbo.Split(chv.Path,''/'') chvS
	left join Classification.Classification cDesc
on cxc.ChildClassificationID = cDesc.ClassificationID
    left join Classification.ClassificationDataConcept cdc
    on c.ClassificationDataConceptID = cdc.ClassificationDataConceptID


    left join Classification.ClassificationXClassification cxc2
    on cDesc.ClassificationID = cxc2.ParentClassificationID
    left join Classification.Classification cDesc2
    on cxc2.ChildClassificationID = cDesc2.ClassificationID

    left join Classification.ClassificationXClassification cxc3
    on cDesc2.ClassificationID = cxc3.ParentClassificationID
    left join Classification.Classification cDesc3
    on cxc3.ChildClassificationID = cDesc3.ClassificationID


    left join Classification.ClassificationXClassification cxc4
    on cDesc3.ClassificationID = cxc4.ParentClassificationID
    left join Classification.Classification cDesc4
    on cxc4.ChildClassificationID = cDesc4.ClassificationID

where chvS.items = c.ClassificationID
' 
GO
