SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
IF NOT EXISTS (SELECT * FROM sys.views WHERE object_id = OBJECT_ID(N'[dbo].[ArrangementHierarchyView]'))
EXEC dbo.sp_executesql @statement = N'


--drop view [dbo].[SecurityHierarchyView];
CREATE view [dbo].[ArrangementHierarchyView]
AS
    with tbl AS
    (
    select st.ArrangementID        ''id''
    , st.ArrangementID        ''name''
    , sxs.ParentArrangementID ''ParentID''
    from Arrangement.ArrangementXArrangement sxs (nolock)
    right outer join Arrangement.Arrangement st (nolock)
    on sxs.ChildArrangementID = st.ArrangementID
    left join Arrangement.Arrangement stChild (nolock)
    on sxs.ChildArrangementID = stChild.ArrangementID
),
    SecurityPath
AS (
    -- anchor
    SELECT CONVERT(VARCHAR(36),id) id,
    CONVERT(VARCHAR(36),[Name]) [Name],
    CONVERT(VARCHAR(36),ParentID) ParentID,
    CONVERT(VARCHAR(1500),[Name]) AS "Pather",
    CONVERT(VARCHAR(1500),id)  AS "Path"
    FROM tbl
    WHERE ParentId IS NULL
    UNION ALL
    --recursive member
    SELECT  CONVERT(VARCHAR(36),t.id) id,
    CONVERT(VARCHAR(36),t.[Name]) [Name],
    CONVERT(VARCHAR(36),t.ParentID) ParentID,
    CAST(CONVERT(VARCHAR(36),a.name) + ''/'' + (CONVERT(VARCHAR(36),t.Name)) AS VARCHAR(1500)) AS "Path",
    CAST((a."Path" + ''/'' + convert(VARCHAR(36),t.id)) AS VARCHAR(1500)) AS "PathCrypt"
    FROM tbl AS t
    JOIN SecurityPath AS a
    ON t.ParentId = a.id
)
SELECT s.id, s.Name, s.ParentID, s.Pather, s.Path, ''1'' as ''One''
FROM SecurityPath s
' 
GO
/****** Object:  View [dbo].[ClassificationsGroupings]    Script Date: 2021/11/03 04:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
IF NOT EXISTS (SELECT * FROM sys.views WHERE object_id = OBJECT_ID(N'[dbo].[ClassificationsGroupings]'))
EXEC dbo.sp_executesql @statement = N'

CREATE view [dbo].[ClassificationsGroupings]
as
select cdc.ClassificationDataConceptName ''Concept'', parent.ClassificationName ''Parent'', child.ClassificationName ''Child'', cType.ClassificationName ''Type''
from Classification.ClassificationXClassification cxc
         inner join Classification.Classification parent
                    on cxc.ParentClassificationID = parent.ClassificationID
         inner join Classification.Classification child
                    on cxc.ChildClassificationID = child.ClassificationID
         inner join Classification.ClassificationDataConcept cdc
                    on child.ClassificationDataConceptID = cdc.ClassificationDataConceptID
         inner join Classification.Classification cType
                    on cxc.ClassificationID = cType.ClassificationID

' 
GO
