/****** Object:  View [dbo].[ResourceTypeClassificationsView]    Script Date: 2021/11/03 04:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
IF NOT EXISTS (SELECT * FROM sys.views WHERE object_id = OBJECT_ID(N'[dbo].[ResourceTypeClassificationsView]'))
EXEC dbo.sp_executesql @statement = N'

CREATE View [dbo].[ResourceTypeClassificationsView]
AS
select ri.ResourceItemID,
       typ.ResourceItemTypeName,
       t.value                                ''TypeValue'',
       c.ClassificationName,
       rc.value                               ''ClassificationValue'',
       cast(ResourceItemData as varchar(max)) ''Data''
        ,
       resourceItemDataType
from Resource.ResourceItem ri
         left join Resource.ResourceItemXClassification rc (nolock)
                   on ri.ResourceItemID = rc.ResourceItemID
         left join Classification.Classification c (nolock)
                   on rc.classificationID = c.classificationID
         left join Resource.ResourceItemXResourceItemType t (nolock)
                   on ri.resourceItemID = t.resourceItemID
         left join Resource.ResourceItemType typ (nolock)
                   on t.ResourceItemTypeID = typ.ResourceItemTypeID
         left join Resource.ResourceItemData dat
                   on ri.ResourceItemID = dat.ResourceItemID
' 
GO
