/****** Object:  StoredProcedure [dbo].[GetDatabaseDictionary]    Script Date: 2021/11/03 04:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
IF NOT EXISTS (SELECT * FROM sys.objects WHERE object_id = OBJECT_ID(N'[dbo].[GetDatabaseDictionary]') AND type in (N'P', N'PC'))
BEGIN
EXEC dbo.sp_executesql @statement = N'CREATE PROCEDURE [dbo].[GetDatabaseDictionary] AS' 
END
GO

-- =============================================
-- Author:		Marc Magon
-- Create date: 2013/07/31
-- Description:	This procedure will get all database dictionary fields
-- =============================================
ALTER PROCEDURE [dbo].[GetDatabaseDictionary]
AS
BEGIN
SELECT OBJECT_NAME(ISNULL(col.object_id, major_id)) ObjectName, ISNULL(col.name, 'TableDefinition'), ep.name, ep.value
FROM sys.columns col
         FULL OUTER JOIN sys.extended_properties ep
                         ON col.object_id = ep.major_id
                             AND col.column_id = ep.minor_id
WHERE ep.name = 'MS_Description'
   or ep.name is null
    --WHERE OBJECT_NAME(col.object_id) = 'IP_X_IP_NM_TP'
    --OR OBJECT_NAME(ep.major_id) = 'IP_X_IP_NM_TP'
    and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sql%'
    and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysa%'
    and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysb%'
    and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysc%'
    and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysd%'
    and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'syse%'
    and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysf%'
    and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysg%'
    and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysh%'
