BEGIN
EXEC dbo.sp_executesql @statement = N'CREATE PROCEDURE [dbo].[UpdateHierarchyAll] AS' 
END
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
ALTER PROCEDURE [dbo].[UpdateHierarchyAll]
AS
BEGIN
UPDATE Security.SecurityHierarchy
SET Path     = v.Path,
    ParentID = v.ParentID,
    Pather   = v.Pather
    FROM Security.SecurityHierarchy (nolock) sh
             inner join Security.SecurityHierarchyView (nolock) v
on sh.id = v.id
where sh.Path <> v.Path
END
GO
